import { Router } from "express";
import { ServiceError } from "../types.js";
import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/productService.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const parsedMin =
    typeof minPrice === "string" ? parseFloat(minPrice) : NaN;
  const parsedMax =
    typeof maxPrice === "string" ? parseFloat(maxPrice) : NaN;

  const result = listProducts({
    category: typeof category === "string" ? category : undefined,
    minPrice: isNaN(parsedMin) ? undefined : parsedMin,
    maxPrice: isNaN(parsedMax) ? undefined : parsedMax,
  });

  res.json(result);
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const product = getProductById(id);
    res.json(product);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: unknown };
    const product = adjustProductStock(id, adjustment);
    res.json(product);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

export { router as productRouter };

